def create_connection():
    """Create a secure RabbitMQ connection using TLS and credentials from environment."""
    rabbitmq_host = os.environ.get("RABBITMQ_HOST", "localhost")
    rabbitmq_port = int(os.environ.get("RABBITMQ_PORT", "5671"))  # TLS port
    rabbitmq_user = os.environ.get("RABBITMQ_USER")
    rabbitmq_pass = os.environ.get("RABBITMQ_PASS")
    rabbitmq_vhost = os.environ.get("RABBITMQ_VHOST", "/")

    if not rabbitmq_user or not rabbitmq_pass:
        raise RuntimeError(
            "RabbitMQ credentials not configured. "
            "Set RABBITMQ_USER and RABBITMQ_PASS environment variables."
        )

    # Use TLS for transport security
    ca_cert_path = os.environ.get("RABBITMQ_CA_CERT", "/etc/ssl/certs/rabbitmq-ca.pem")
    client_cert_path = os.environ.get("RABBITMQ_CLIENT_CERT", "/etc/ssl/certs/rabbitmq-client.pem")
    client_key_path = os.environ.get("RABBITMQ_CLIENT_KEY", "/etc/ssl/private/rabbitmq-client-key.pem")

    import ssl
    ssl_context = ssl.create_default_context(cafile=ca_cert_path)
    ssl_context.load_cert_chain(certfile=client_cert_path, keyfile=client_key_path)
    ssl_context.check_hostname = True
    ssl_context.verify_mode = ssl.CERT_REQUIRED

    ssl_options = pika.SSLOptions(ssl_context, server_hostname=rabbitmq_host)

    credentials = pika.PlainCredentials(rabbitmq_user, rabbitmq_pass)

    connection_params = pika.ConnectionParameters(
        host=rabbitmq_host,
        port=rabbitmq_port,
        virtual_host=rabbitmq_vhost,
        credentials=credentials,
        ssl_options=ssl_options,
        heartbeat=600,
        blocked_connection_timeout=300,
    )

    return pika.BlockingConnection(connection_params)


